INSERT INTO `blogpost` VALUES ('cmk157crh04czul9sjh3pojeq','welcome-to-bohosaaz','Welcome to Bohosaaz','A premium marketplace for handcrafted goods.','# Welcome\n\nDiscover artisan-made pieces with transparent pricing and trusted sellers.',NULL,1,'2026-01-05 12:34:24.220','2026-01-05 12:34:24.221','2026-01-05 12:34:24.221',NULL),('cmk157crh04d0ul9snu3fhk7j','craft-first-quality','Craft-first quality','How we curate sellers and products.','## Our curation\n\nWe prioritize authentic handmade products and small-batch production.',NULL,1,'2026-01-05 12:34:24.220','2026-01-05 12:34:24.221','2026-01-05 12:34:24.221',NULL),('cmk157crh04d1ul9srnsuwcgl','behind-the-scenes','Behind the scenes','A look at how orders flow across vendors.','## Order flow\n\nOrders are fulfilled vendor-wise with clear tracking and payouts.',NULL,0,NULL,'2026-01-05 12:34:24.221','2026-01-05 12:34:24.221',NULL);
