--
-- Table structure for table `razorpaytopup`
--

DROP TABLE IF EXISTS `razorpaytopup`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `razorpaytopup` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `walletId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `userId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `amountPaise` bigint NOT NULL,
  `status` enum('CREATED','PAID','FAILED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'CREATED',
  `razorpayOrderId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `razorpayPaymentId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `RazorpayTopup_razorpayOrderId_key` (`razorpayOrderId`),
  UNIQUE KEY `RazorpayTopup_razorpayPaymentId_key` (`razorpayPaymentId`),
  KEY `RazorpayTopup_userId_idx` (`userId`),
  KEY `RazorpayTopup_walletId_idx` (`walletId`),
  KEY `RazorpayTopup_status_idx` (`status`),
  CONSTRAINT `RazorpayTopup_userId_fkey` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `RazorpayTopup_walletId_fkey` FOREIGN KEY (`walletId`) REFERENCES `walletaccount` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

