DROP TABLE IF EXISTS `userticket`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `userticket` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `userId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` enum('ORDER','PAYMENT','RETURN','GENERAL') COLLATE utf8mb4_unicode_ci NOT NULL,
  `subject` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('OPEN','IN_PROGRESS','RESOLVED','CLOSED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'OPEN',
  `priority` enum('LOW','MEDIUM','HIGH','URGENT') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'MEDIUM',
  `orderId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `returnRequestId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta` json DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `UserTicket_userId_idx` (`userId`),
  KEY `UserTicket_status_idx` (`status`),
  KEY `UserTicket_priority_idx` (`priority`),
  KEY `UserTicket_category_idx` (`category`),
  KEY `UserTicket_orderId_fkey` (`orderId`),
  KEY `UserTicket_returnRequestId_fkey` (`returnRequestId`),
  CONSTRAINT `UserTicket_orderId_fkey` FOREIGN KEY (`orderId`) REFERENCES `order` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `UserTicket_returnRequestId_fkey` FOREIGN KEY (`returnRequestId`) REFERENCES `returnrequest` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `UserTicket_userId_fkey` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

