--
-- Table structure for table `walletaccount`
--

DROP TABLE IF EXISTS `walletaccount`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `walletaccount` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kind` enum('USER','VENDOR','PLATFORM') COLLATE utf8mb4_unicode_ci NOT NULL,
  `platformKey` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `userId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `vendorId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `balancePaise` bigint NOT NULL DEFAULT '0',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `WalletAccount_platformKey_key` (`platformKey`),
  UNIQUE KEY `WalletAccount_userId_key` (`userId`),
  UNIQUE KEY `WalletAccount_vendorId_key` (`vendorId`),
  KEY `WalletAccount_kind_idx` (`kind`),
  CONSTRAINT `WalletAccount_userId_fkey` FOREIGN KEY (`userId`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `WalletAccount_vendorId_fkey` FOREIGN KEY (`vendorId`) REFERENCES `vendor` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

