--
-- Table structure for table `wallettransaction`
--

DROP TABLE IF EXISTS `wallettransaction`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wallettransaction` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `idempotencyKey` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `walletId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` enum('TOPUP','ORDER_PAYMENT','REFUND','PAYOUT','COMMISSION','ADJUSTMENT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `direction` enum('CREDIT','DEBIT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('PENDING','POSTED','FAILED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'POSTED',
  `amountPaise` bigint NOT NULL,
  `balanceAfterPaise` bigint NOT NULL,
  `currency` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'INR',
  `note` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta` json DEFAULT NULL,
  `orderId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `vendorOrderId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payoutId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `razorpayOrderId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `razorpayPaymentId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`),
  UNIQUE KEY `WalletTransaction_idempotencyKey_key` (`idempotencyKey`),
  KEY `WalletTransaction_walletId_createdAt_idx` (`walletId`,`createdAt`),
  KEY `WalletTransaction_type_idx` (`type`),
  KEY `WalletTransaction_orderId_idx` (`orderId`),
  KEY `WalletTransaction_vendorOrderId_idx` (`vendorOrderId`),
  KEY `WalletTransaction_payoutId_idx` (`payoutId`),
  KEY `WalletTransaction_razorpayOrderId_idx` (`razorpayOrderId`),
  KEY `WalletTransaction_razorpayPaymentId_idx` (`razorpayPaymentId`),
  CONSTRAINT `WalletTransaction_orderId_fkey` FOREIGN KEY (`orderId`) REFERENCES `order` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `WalletTransaction_payoutId_fkey` FOREIGN KEY (`payoutId`) REFERENCES `payout` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `WalletTransaction_vendorOrderId_fkey` FOREIGN KEY (`vendorOrderId`) REFERENCES `vendororder` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `WalletTransaction_walletId_fkey` FOREIGN KEY (`walletId`) REFERENCES `walletaccount` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `wallettransaction`
--

LOCK TABLES `wallettransaction` WRITE;
/*!40000 ALTER TABLE `wallettransaction` DISABLE KEYS */;
